  sentences = []
      for subj, actions in subject_map.items():
          if not actions:
              continue
          # use the first predicate as the main clause
          main_clause = actions[0]
          if len(actions) == 1:
              sentences.append(f"{subj} {main_clause}")
          else:
              # remaining predicates become relative clauses starting with “which”
              rel_clauses = [f"which {act}" for act in actions[1:]]
              if len(rel_clauses) == 1:
                  rel_part = rel_clauses[0]
              else:
                  rel_part = ", ".join(rel_clauses[:-1]) + ", and " + rel_clauses[-1]
              sentences.append(f"{subj} {main_clause}, {rel_part}")

      if not sentences:
          return ""
      if len(sentences) == 1:
          return sentences[0] + "."
      # combine multiple subject clauses into one complex sentence
      return ", ".join(sentences[:-1]) + ", and " + sentences[-1] + "."
